function decodeBase64Url(value) {
  if (!value || typeof value !== "string") return "";

  try {
    const normalized = value.replace(/-/g, "+").replace(/_/g, "/");
    return Buffer.from(normalized, "base64").toString("utf8");
  } catch (error) {
    return value;
  }
}

function extractTextFromGmailPayload(payload) {
  if (!payload) return "";


  if (payload.body?.data) {
    return decodeBase64Url(payload.body.data);
  }


  if (Array.isArray(payload.parts)) {
    const textParts = [];

    function walkParts(parts) {
      for (const part of parts) {
        if (part.mimeType === "text/plain" && part.body?.data) {
          textParts.push(decodeBase64Url(part.body.data));
        }

        if (part.mimeType === "text/html" && part.body?.data && textParts.length === 0) {
          textParts.push(decodeBase64Url(part.body.data));
        }

        if (Array.isArray(part.parts)) {
          walkParts(part.parts);
        }
      }
    }

    walkParts(payload.parts);

    return textParts.join(" ");
  }

  return "";
}

function cleanHtmlAndSpaces(value) {
  return String(value || "")
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<[^>]*>/g, " ")
    .replace(/&nbsp;/gi, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">")
    .replace(/\r?\n/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeName(value) {
  return String(value || "")
    .normalize("NFC")
    .replace(/\s+/g, " ")
    .trim();
}

function makeSafeFileName(value) {
  return String(value || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/ñ/gi, "n")
    .replace(/[^a-zA-Z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "")
    .toLowerCase();
}


if (
  !CONFIG.supabaseUrl ||
  !CONFIG.supabaseUrl.startsWith("https://") ||
  CONFIG.supabaseUrl.includes("TU_PROJECT_ID") ||
  !CONFIG.supabaseServiceRoleKey ||
  CONFIG.supabaseServiceRoleKey.includes("TU_SERVICE_ROLE_KEY") ||
  CONFIG.supabaseServiceRoleKey.includes("REEMPLAZAR") ||
  CONFIG.supabaseServiceRoleKey.includes("PEGA_AQUI")
) {
  throw new Error(
    "Configura supabaseUrl y supabaseServiceRoleKey en el nodo 'Preparar entrada, validar nombre y parámetros'."
  );
}

if (!CONFIG.recipientEmail || !CONFIG.recipientEmail.includes("@")) {
  throw new Error("Configura recipientEmail con un correo válido.");
}

if (!CONFIG.baseUrl.startsWith("https://consultaprocesos.ramajudicial.gov.co")) {
  throw new Error("La baseUrl no corresponde al dominio esperado de Rama Judicial.");
}

if (!CONFIG.chromiumPath) {
  throw new Error("Configura chromiumPath. Para tu contenedor debe ser /usr/bin/chromium-browser.");
}


const gmailPayloadText = extractTextFromGmailPayload(input.payload);

const rawBody = String(
  input.textPlain ||
  input.text ||
  input.body ||
  input.message ||
  gmailPayloadText ||
  input.html ||
  input.snippet ||
  input.payload?.body?.data ||
  ""
);

let decodedBody = rawBody;

try {

  if (/^[A-Za-z0-9_-]+={0,2}$/.test(rawBody) && rawBody.length > 20) {
    decodedBody = decodeBase64Url(rawBody);
  }
} catch (error) {
  decodedBody = rawBody;
}

const cleanBody = cleanHtmlAndSpaces(decodedBody);



const explicitMatch = cleanBody.match(
  /(?:nombre\s*(?:completo)?|persona\s*(?:a\s*consultar)?|consultar)\s*[:\-]\s*([A-Za-zÁÉÍÓÚÜÑáéíóúüñ]+(?:\s+[A-Za-zÁÉÍÓÚÜÑáéíóúüñ]+){1,6})/i
);

const fallbackMatch = cleanBody.match(
  /^([A-Za-zÁÉÍÓÚÜÑáéíóúüñ]+(?:\s+[A-Za-zÁÉÍÓÚÜÑáéíóúüñ]+){1,6})$/i
);

const nombreConsulta = normalizeName(explicitMatch?.[1] || fallbackMatch?.[1] || "");

if (!nombreConsulta || nombreConsulta.split(" ").length < 2) {
  throw new Error(
    `No se detectó un nombre válido en el cuerpo del correo. Texto recibido: "${cleanBody}"`
  );
}


const now = new Date();
const fechaEjecucion = now.toISOString().slice(0, 10);
const fechaHoraEjecucion = now.toISOString();
const runId = `${fechaEjecucion}_${Date.now()}`;

const safeNombre = makeSafeFileName(nombreConsulta);

const expectedDocFileName = `detalle_proceso_${safeNombre}_${fechaEjecucion}.doc`;

const supabaseFilePath = `consultas/${fechaEjecucion}/${runId}/${expectedDocFileName}`;

const emailSubject = `[RPA] Detalle Proceso - ${nombreConsulta} - ${fechaEjecucion}`;

const emailBody = `
<p>Hola,</p>

<p>Se ejecutó la consulta judicial solicitada.</p>

<ul>
  <li><strong>Nombre consultado:</strong> ${nombreConsulta}</li>
  <li><strong>Fecha de ejecución:</strong> ${fechaEjecucion}</li>
  <li><strong>Fecha y hora técnica:</strong> ${fechaHoraEjecucion}</li>
  <li><strong>Fuente de consulta:</strong> ${CONFIG.baseUrl}</li>
</ul>

<p>Se adjunta el documento DOC descargado desde el detalle del proceso.</p>
<p>También se generará una URL temporal de Supabase como respaldo documental.</p>
`;



return [
  {
    json: {
      ...CONFIG,


      sourceMessageId: input.id || input.messageId || "",
      sourceThreadId: input.threadId || "",
      sourceSubject: input.subject || "",
      sourceFrom: input.from || input.fromEmail || input.sender || "",
      rawBody: cleanBody,


      nombreConsulta,
      safeNombre,


      fechaEjecucion,
      fechaHoraEjecucion,
      runId,


      expectedDocFileName,
      supabaseFilePath,


      emailSubject,
      emailBody
    }
  }
];

const stdout = String($json.stdout || "");
const stderr = String($json.stderr || "");
const exitCode = $json.exitCode ?? $json.code ?? null;

// Validación mínima: el nodo Execute Command debe entregar stdout
if (!stdout && !stderr) {
  throw new Error(
    `El nodo Execute Command no entregó stdout ni stderr. JSON recibido: ${JSON.stringify($json).slice(0, 2000)}`
  );
}

// Buscar la salida marcada del RPA
const match = stdout.match(/__RPA_RESULT_START__\s*([\s\S]*?)\s*__RPA_RESULT_END__/);

if (!match) {
  throw new Error(
    [
      "No se pudo leer la salida JSON del RPA.",
      `ExitCode: ${exitCode}`,
      `STDOUT: ${stdout.slice(0, 3000)}`,
      `STDERR: ${stderr.slice(0, 3000)}`
    ].join("\n")
  );
}

let rpa;

try {
  rpa = JSON.parse(match[1]);
} catch (error) {
  throw new Error(
    [
      "La salida del RPA no es JSON válido.",
      `Error: ${error.message}`,
      `Salida capturada: ${match[1].slice(0, 3000)}`
    ].join("\n")
  );
}

// Normalizar campos para evitar undefined
const rpaMessage = rpa.message || rpa.error || rpa.errorMessage || "Error no especificado";
const rpaLogFile = rpa.logFile || rpa.logPath || "No generado";
const rpaScreenshot = rpa.screenshotPath || "No generado";

if (rpa.success !== true) {
  throw new Error(
    `[RPA FALLÓ] ${rpaMessage}. Log: ${rpaLogFile}. Screenshot: ${rpaScreenshot}`
  );
}

const emailBody = `
<p>Hola,</p>

<p>Se ejecutó la consulta judicial solicitada.</p>

<ul>
  <li><strong>Nombre consultado:</strong> ${rpa.nombreConsulta}</li>
  <li><strong>Fecha de ejecución:</strong> ${rpa.fechaEjecucion}</li>
  <li><strong>URL del proceso:</strong> ${rpa.processUrl}</li>
  <li><strong>Resultado seleccionado:</strong> ${rpa.sixthResultText || "Sexto resultado de la lista"}</li>
  <li><strong>Archivo generado:</strong> ${rpa.downloadedFileName || rpa.expectedDocFileName}</li>
</ul>

<p>Se adjunta el documento DOC descargado.</p>
`;

return [
  {
    json: {
      ...rpa,
      emailSubject: `[RPA] Detalle Proceso - ${rpa.nombreConsulta} - ${rpa.fechaEjecucion}`,
      emailBody
    }
  }
];

