={{
`
cd /usr/local/lib/node_modules/n8n && node <<'NODE'
const fs = require("fs");
const path = require("path");
const { chromium } = require("playwright");

const input = ${JSON.stringify($json)};
const logFile = path.join(input.logDir, "ejecuciones_rpa_consulta_judicial.jsonl");

function ensureDir(dir) {
  fs.mkdirSync(dir, { recursive: true });
}

function writeLog(event) {
  ensureDir(input.logDir);
  fs.appendFileSync(
    logFile,
    JSON.stringify({
      timestamp: new Date().toISOString(),
      runId: input.runId,
      nombreConsulta: input.nombreConsulta,
      ...event
    }) + String.fromCharCode(10),
    "utf8"
  );
}

function emit(result) {
  console.log("__RPA_RESULT_START__");
  console.log(JSON.stringify(result));
  console.log("__RPA_RESULT_END__");
}

function stripDiacritics(value) {
  const text = String(value || "").normalize("NFD");
  let output = "";

  for (const char of text) {
    const code = char.charCodeAt(0);
    if (code < 768 || code > 879) {
      output += char;
    }
  }

  return output;
}

function cleanText(value) {
  const text = stripDiacritics(value);
  let output = "";
  let previousWasSpace = false;

  for (const char of text) {
    const code = char.charCodeAt(0);
    const isSpace = code <= 32 || code === 160;

    if (isSpace) {
      if (!previousWasSpace) {
        output += " ";
        previousWasSpace = true;
      }
    } else {
      output += char;
      previousWasSpace = false;
    }
  }

  return output.trim();
}

function normalizeText(value) {
  return cleanText(value).toLowerCase();
}

function digitsOnly(value) {
  const text = String(value || "");
  let output = "";

  for (const char of text) {
    if (char >= "0" && char <= "9") {
      output += char;
    }
  }

  return output;
}

async function getBodyText(page) {
  return await page
    .evaluate(() => document.body.innerText || document.body.textContent || "")
    .catch(() => "");
}

async function isDetailPage(page, expectedRadicado) {
  const text = await getBodyText(page);
  const digits = digitsOnly(text);

  const hasDetail =
    text.includes("DETALLE DEL PROCESO") ||
    text.includes("REPORTE DEL PROCESO") ||
    text.includes("Datos del Proceso") ||
    text.includes("DATOS DEL PROCESO") ||
    text.includes("Fecha de consulta") ||
    text.includes("Fecha de la consulta") ||
    text.includes("Actuaciones del Proceso") ||
    text.includes("Sujetos Procesales");

  const hasRadicado = expectedRadicado ? digits.includes(expectedRadicado) : digits.length > 15;

  return hasDetail && hasRadicado;
}

async function tryAction(label, actions) {
  let lastError = null;

  for (const action of actions) {
    try {
      return await action();
    } catch (error) {
      lastError = error;
    }
  }

  throw new Error(
    label + ": " + (lastError && lastError.message ? lastError.message : "No se pudo ejecutar la acción")
  );
}

async function selectNaturalPerson(page) {
  await tryAction("Seleccionar Tipo de Persona Natural", [
    async () => {
      const field = page
        .locator("mat-form-field, .mat-mdc-form-field, .mat-form-field, div")
        .filter({ hasText: /Tipo de Persona/i })
        .first();

      await field.click({ timeout: 10000, force: true });
      await page.waitForTimeout(800);

      await page
        .locator("mat-option, .mat-mdc-option, [role='option'], div, span")
        .filter({ hasText: /^Natural$/i })
        .first()
        .click({ timeout: 10000, force: true });
    },

    async () => {
      await page.getByText(/Tipo de Persona/i).first().click({
        timeout: 10000,
        force: true
      });

      await page.waitForTimeout(800);

      await page.getByText(/^Natural$/i).first().click({
        timeout: 10000,
        force: true
      });
    },

    async () => {
      const opened = await page.evaluate(() => {
        const cleanLocal = (value) => {
          const text = String(value || "").normalize("NFD");
          let noAccents = "";

          for (const char of text) {
            const code = char.charCodeAt(0);
            if (code < 768 || code > 879) {
              noAccents += char;
            }
          }

          let output = "";
          let previousWasSpace = false;

          for (const char of noAccents) {
            const code = char.charCodeAt(0);
            const isSpace = code <= 32 || code === 160;

            if (isSpace) {
              if (!previousWasSpace) {
                output += " ";
                previousWasSpace = true;
              }
            } else {
              output += char;
              previousWasSpace = false;
            }
          }

          return output.trim().toLowerCase();
        };

        const fields = Array.from(
          document.querySelectorAll("mat-form-field, .mat-mdc-form-field, .mat-form-field, div")
        );

        const field = fields.find((el) => cleanLocal(el.textContent).includes("tipo de persona"));

        if (!field) return false;

        const clickable =
          field.querySelector("mat-select") ||
          field.querySelector(".mat-mdc-select") ||
          field.querySelector(".mat-select") ||
          field.querySelector("[role='combobox']") ||
          field;

        clickable.scrollIntoView({
          block: "center",
          inline: "center"
        });

        clickable.click();

        return true;
      });

      if (!opened) {
        throw new Error("No se pudo abrir el dropdown Tipo de Persona.");
      }

      await page.waitForTimeout(800);

      const selected = await page.evaluate(() => {
        const cleanLocal = (value) => {
          const text = String(value || "").normalize("NFD");
          let noAccents = "";

          for (const char of text) {
            const code = char.charCodeAt(0);
            if (code < 768 || code > 879) {
              noAccents += char;
            }
          }

          let output = "";
          let previousWasSpace = false;

          for (const char of noAccents) {
            const code = char.charCodeAt(0);
            const isSpace = code <= 32 || code === 160;

            if (isSpace) {
              if (!previousWasSpace) {
                output += " ";
                previousWasSpace = true;
              }
            } else {
              output += char;
              previousWasSpace = false;
            }
          }

          return output.trim().toLowerCase();
        };

        const options = Array.from(
          document.querySelectorAll("mat-option, .mat-mdc-option, [role='option'], .mat-option, div, span")
        );

        const natural = options.find((el) => cleanLocal(el.textContent) === "natural");

        if (!natural) return false;

        natural.scrollIntoView({
          block: "center",
          inline: "center"
        });

        natural.click();
        natural.dispatchEvent(new MouseEvent("click", { bubbles: true }));

        return true;
      });

      if (!selected) {
        throw new Error("No se encontró la opción Natural después de abrir el dropdown.");
      }
    }
  ]);

  await page.waitForTimeout(800);
}

async function fillPersonName(page, nombreConsulta) {
  await tryAction("Ingresar nombre consultado", [
    async () => {
      const nameField = page
        .locator("mat-form-field, .mat-mdc-form-field, .mat-form-field, div")
        .filter({ hasText: /Nombre|Apellido|Razón Social|Razon Social/i })
        .first();

      const visibleInput = nameField.locator("input:not([type='hidden']), textarea").first();

      await visibleInput.fill(nombreConsulta, { timeout: 10000 });
    },

    async () => {
      const inputByAttr = page
        .locator(
          "input[placeholder*='Nombre'], input[placeholder*='Apellido'], input[placeholder*='Razón'], input[placeholder*='Razon'], input[aria-label*='Nombre'], input[aria-label*='Apellido'], input[aria-label*='Razón'], input[aria-label*='Razon']"
        )
        .first();

      await inputByAttr.fill(nombreConsulta, { timeout: 10000 });
    },

    async () => {
      const filled = await page.evaluate((nombre) => {
        const isVisible = (el) => {
          const style = window.getComputedStyle(el);
          const rect = el.getBoundingClientRect();

          return (
            style.display !== "none" &&
            style.visibility !== "hidden" &&
            style.opacity !== "0" &&
            rect.width > 0 &&
            rect.height > 0
          );
        };

        const setNativeValue = (el, value) => {
          const prototype = Object.getPrototypeOf(el);
          const descriptor = Object.getOwnPropertyDescriptor(prototype, "value");

          if (descriptor && descriptor.set) {
            descriptor.set.call(el, value);
          } else {
            el.value = value;
          }

          el.dispatchEvent(new Event("input", { bubbles: true }));
          el.dispatchEvent(new Event("change", { bubbles: true }));
          el.dispatchEvent(new Event("blur", { bubbles: true }));
        };

        const inputs = Array.from(document.querySelectorAll("input:not([type='hidden']), textarea")).filter(
          (el) => !el.disabled && !el.readOnly && isVisible(el)
        );

        for (const el of inputs) {
          const attrText = String(
            [
              el.name,
              el.id,
              el.placeholder,
              el.getAttribute("aria-label"),
              el.getAttribute("formcontrolname"),
              el.getAttribute("ng-reflect-name"),
              el.getAttribute("autocomplete")
            ].join(" ")
          ).toLowerCase();

          if (
            attrText.includes("nombre") ||
            attrText.includes("apellido") ||
            attrText.includes("razon") ||
            attrText.includes("social")
          ) {
            el.focus();
            setNativeValue(el, nombre);
            return true;
          }
        }

        for (const el of inputs) {
          const container = el.closest("mat-form-field, .mat-mdc-form-field, .mat-form-field, div, section, form");
          const containerText = String(container ? container.textContent : "").toLowerCase();

          if (
            containerText.includes("nombre") ||
            containerText.includes("apellido") ||
            containerText.includes("razon social") ||
            containerText.includes("razon")
          ) {
            el.focus();
            setNativeValue(el, nombre);
            return true;
          }
        }

        return false;
      }, nombreConsulta);

      if (!filled) {
        throw new Error("No se encontró input visible y editable para ingresar el nombre.");
      }
    }
  ]);

  await page.waitForTimeout(800);
}

async function getSearchFormState(page, expectedName) {
  return await page.evaluate((nombreEsperado) => {
    const clean = (value) => {
      const text = String(value || "");
      let output = "";
      let previousWasSpace = false;

      for (const char of text) {
        const code = char.charCodeAt(0);
        const isSpace = code <= 32 || code === 160;

        if (isSpace) {
          if (!previousWasSpace) {
            output += " ";
            previousWasSpace = true;
          }
        } else {
          output += char;
          previousWasSpace = false;
        }
      }

      return output.trim();
    };

    const strip = (value) => {
      const text = String(value || "").normalize("NFD");
      let output = "";

      for (const char of text) {
        const code = char.charCodeAt(0);
        if (code < 768 || code > 879) {
          output += char;
        }
      }

      return output;
    };

    const normalize = (value) => clean(strip(value)).toLowerCase();

    const isVisible = (el) => {
      const style = window.getComputedStyle(el);
      const rect = el.getBoundingClientRect();

      return (
        style.display !== "none" &&
        style.visibility !== "hidden" &&
        style.opacity !== "0" &&
        rect.width > 0 &&
        rect.height > 0
      );
    };

    const expected = normalize(nombreEsperado);

    const inputs = Array.from(document.querySelectorAll("input:not([type='hidden']), textarea"))
      .filter((el) => isVisible(el));

    const inputValues = inputs.map((el) => ({
      value: clean(el.value),
      placeholder: clean(el.placeholder),
      name: clean(el.name),
      id: clean(el.id),
      ariaLabel: clean(el.getAttribute("aria-label")),
      formcontrolname: clean(el.getAttribute("formcontrolname")),
      containerText: clean(el.closest("mat-form-field, .mat-mdc-form-field, .mat-form-field, div")?.textContent || "")
    }));

    const nameInput = inputValues.find((item) => {
      const metadata = normalize([
        item.placeholder,
        item.name,
        item.id,
        item.ariaLabel,
        item.formcontrolname,
        item.containerText
      ].join(" "));

      return (
        metadata.includes("nombre") ||
        metadata.includes("apellido") ||
        metadata.includes("razon") ||
        metadata.includes("social")
      );
    });

    const visibleBodyText = clean(document.body.innerText || document.body.textContent || "");
    const nameValue = nameInput ? nameInput.value : "";
    const normalizedValue = normalize(nameValue);

    const nameOk =
      normalizedValue.length > 0 &&
      (
        normalizedValue.includes(expected) ||
        expected.includes(normalizedValue)
      );

    return {
      nameOk,
      nameValue,
      expectedName: nombreEsperado,
      inputValues,
      bodySample: visibleBodyText.slice(0, 1800)
    };
  }, expectedName);
}

async function ensureNameWasFilled(page, nombreConsulta) {
  let state = await getSearchFormState(page, nombreConsulta);

  if (state.nameOk) {
    writeLog({
      level: "INFO",
      step: "FORM_NAME_VALIDATED",
      nameValue: state.nameValue
    });

    return;
  }

  writeLog({
    level: "WARN",
    step: "FORM_NAME_NOT_FILLED_RETRY",
    expectedName: nombreConsulta,
    state
  });

  await fillPersonName(page, nombreConsulta);
  await page.waitForTimeout(1000);

  state = await getSearchFormState(page, nombreConsulta);

  if (!state.nameOk) {
    throw new Error(
      "El campo de nombre no quedó diligenciado antes de consultar. Nombre esperado: " +
        nombreConsulta +
        ". Estado formulario: " +
        JSON.stringify(state).slice(0, 2500)
    );
  }

  writeLog({
    level: "INFO",
    step: "FORM_NAME_VALIDATED_AFTER_RETRY",
    nameValue: state.nameValue
  });
}

async function hasResultsLoaded(page) {
  return await page.evaluate(() => {
    const text = document.body.innerText || document.body.textContent || "";
    const parts = String(text || "").split(/[ \\t\\r\\n]+/);

    const digitGroups = [];

    for (const part of parts) {
      let digits = "";

      for (const char of part) {
        if (char >= "0" && char <= "9") {
          digits += char;
        }
      }

      if (digits.length >= 15 && digits.length <= 30) {
        digitGroups.push(digits);
      }
    }

    const hasResultHeaders =
