async function detectAndOpenSixthResult(page, context) {
  const resultDetection = await page.evaluate(() => {
    const cleanTextLocal = (value) => {
      const text = String(value || "").normalize("NFD");
      let noAccents = "";

      for (const char of text) {
        const code = char.charCodeAt(0);
        if (code < 768 || code > 879) {
          noAccents += char;
        }
      }

      let output = "";
      let previousWasSpace = false;

      for (const char of noAccents) {
        const code = char.charCodeAt(0);
        const isSpace = code <= 32 || code === 160;

        if (isSpace) {
          if (!previousWasSpace) {
            output += " ";
            previousWasSpace = true;
          }
        } else {
          output += char;
          previousWasSpace = false;
        }
      }

      return output.trim();
    };

    const digitsOnlyLocal = (value) => {
      const text = String(value || "");
      let output = "";

      for (const char of text) {
        if (char >= "0" && char <= "9") {
          output += char;
        }
      }

      return output;
    };

    const isVisible = (el) => {
      const style = window.getComputedStyle(el);
      const rect = el.getBoundingClientRect();

      return (
        style.display !== "none" &&
        style.visibility !== "hidden" &&
        style.opacity !== "0" &&
        rect.width > 0 &&
        rect.height > 0
      );
    };

    const clickableScore = (el) => {
      const style = window.getComputedStyle(el);
      const color = style.color || "";
      const cursor = style.cursor || "";
      const rgb = color.match(/[0-9]+/g) || [];
      const r = Number(rgb[0] || 0);
      const g = Number(rgb[1] || 0);
      const b = Number(rgb[2] || 0);

      let score = 0;

      if (b > r && b >= g) score += 4;
      if (cursor === "pointer") score += 4;
      if (el.tagName.toLowerCase() === "a") score += 5;
      if (el.tagName.toLowerCase() === "button") score += 4;
      if (el.getAttribute("role") === "button") score += 4;
      if (typeof el.onclick === "function") score += 3;

      return score;
    };

    const bestClickableForRadicado = (row, radicadoDigits) => {
      const elements = Array.from(
        row.querySelectorAll("a, button, span, div, td, mat-cell, .mat-cell, .mat-mdc-cell, [role='button']")
      )
        .filter(isVisible)
        .map((el) => {
          const text = cleanTextLocal(el.innerText || el.textContent || "");
          const digits = digitsOnlyLocal(text);

          return {
            element: el,
            text,
            digits,
            score: clickableScore(el),
            length: text.length
          };
        })
        .filter((item) => {
          if (!item.digits) return false;
          return item.digits === radicadoDigits || item.digits.includes(radicadoDigits) || radicadoDigits.includes(item.digits);
        });

      elements.sort((a, b) => {
        if (b.score !== a.score) return b.score - a.score;
        return a.length - b.length;
      });

      if (elements.length > 0) return elements[0].element;

      return row;
    };

    document.querySelectorAll("[data-rpa-sixth-result]").forEach((el) => {
      el.removeAttribute("data-rpa-sixth-result");
    });

    const bodyText = cleanTextLocal(document.body.innerText || document.body.textContent || "");

    if (/no se encontraron|sin resultados|no existen registros|no se encontro informacion/i.test(bodyText)) {
      return {
        success: false,
        count: 0,
        message: "La página indica que no hay resultados.",
        bodySample: bodyText.slice(0, 2500)
      };
    }

    const rows = Array.from(document.querySelectorAll("tr, mat-row, .mat-row, .mat-mdc-row, [role='row']")).filter(
      isVisible
    );

    const publicRows = [];

    for (const row of rows) {
      const rowText = cleanTextLocal(row.innerText || row.textContent || "");
      const rowLower = rowText.toLowerCase();

      if (!rowText || rowText.length < 20) continue;
      if (rowLower.includes("numero de radicacion")) continue;
      if (rowLower.includes("número de radicación")) continue;
      if (rowLower.includes("sujetos procesales")) continue;
      if (rowLower.includes("proceso privado")) continue;

      const cells = Array.from(row.querySelectorAll("td, mat-cell, .mat-cell, .mat-mdc-cell, div, span, a, button")).filter(
        isVisible
      );

      let radicadoDigits = "";
      let radicadoText = "";

      for (const cell of cells) {
        const text = cleanTextLocal(cell.innerText || cell.textContent || "");
        const digits = digitsOnlyLocal(text);

        if (digits.length >= 15 && digits.length <= 30 && text.length <= 80) {
          radicadoDigits = digits;
          radicadoText = text;
          break;
        }
      }

      if (!radicadoDigits) {
        const parts = rowText.split(" ");

        for (const part of parts) {
          const digits = digitsOnlyLocal(part);

          if (digits.length >= 15 && digits.length <= 30) {
            radicadoDigits = digits;
            radicadoText = part;
            break;
          }
        }
      }

      if (!radicadoDigits) continue;

      const clickable = bestClickableForRadicado(row, radicadoDigits);

      publicRows.push({
        element: clickable,
        radicado: radicadoDigits,
        text: radicadoText || radicadoDigits,
        rowText: rowText.slice(0, 800)
      });
    }

    if (publicRows.length < 6) {
      return {
        success: false,
        count: publicRows.length,
        message: "No se detectaron 6 filas públicas con radicado.",
        samples: publicRows.map((item, index) => ({
          index: index + 1,
          radicado: item.radicado,
          text: item.text,
          rowText: item.rowText
        })),
        bodySample: bodyText.slice(0, 3500)
      };
    }

    const target = publicRows[5];

    target.element.scrollIntoView({
      block: "center",
      inline: "center"
    });

    target.element.setAttribute("data-rpa-sixth-result", "true");

    return {
      success: true,
      count: publicRows.length,
      sixthText: target.text,
      sixthRadicado: target.radicado,
      samples: publicRows.slice(0, 12).map((item, index) => ({
        index: index + 1,
        radicado: item.radicado,
        text: item.text,
        rowText: item.rowText
      }))
    };
  });

  writeLog({
    level: resultDetection.success ? "INFO" : "ERROR",
    step: "RESULT_DETECTION_PUBLIC_ROWS",
    resultDetection
  });

  if (!resultDetection.success) {
    throw new Error(
      resultDetection.message +
        " Filas públicas detectadas: " +
        resultDetection.count +
        ". Muestras: " +
        JSON.stringify(resultDetection.samples || []).slice(0, 3500) +
        ". Texto pantalla: " +
        String(resultDetection.bodySample || "").slice(0, 3500)
    );
  }

  const popupPromise = context.waitForEvent("page", { timeout: 7000 }).catch(() => null);

  await page.locator("[data-rpa-sixth-result='true']").click({
    timeout: 15000,
    force: true
  });

  let popup = await popupPromise;

  if (popup) {
    page = popup;
    page.setDefaultTimeout(input.timeoutMs || 45000);

    await page.waitForLoadState("domcontentloaded", {
      timeout: input.timeoutMs || 45000
    }).catch(() => {});
  }

  await page.waitForLoadState("networkidle", {
    timeout: input.timeoutMs || 45000
  }).catch(() => {});

  await page.waitForTimeout(4000);

  if (!(await isDetailPage(page, resultDetection.sixthRadicado))) {
    const popupPromise2 = context.waitForEvent("page", { timeout: 7000 }).catch(() => null);

    await page.locator("[data-rpa-sixth-result='true']").dblclick({
      timeout: 15000,
      force: true
    }).catch(async () => {
      await page.locator("[data-rpa-sixth-result='true']").click({
        timeout: 15000,
        force: true
      });
    });

    popup = await popupPromise2;

    if (popup) {
      page = popup;
      page.setDefaultTimeout(input.timeoutMs || 45000);

      await page.waitForLoadState("domcontentloaded", {
        timeout: input.timeoutMs || 45000
      }).catch(() => {});
    }

    await page.waitForLoadState("networkidle", {
      timeout: input.timeoutMs || 45000
    }).catch(() => {});

    await page.waitForTimeout(4000);
  }

  if (!(await isDetailPage(page, resultDetection.sixthRadicado))) {
    const text = await getBodyText(page);

    throw new Error(
      "Después de hacer clic en el sexto radicado público no se abrió el detalle del proceso. Radicado objetivo: " +
        resultDetection.sixthRadicado +
        ". Texto pantalla: " +
        text.slice(0, 2500)
    );
  }

  return {
    page,
    count: resultDetection.count,
    sixthText: resultDetection.sixthText || "Sexto radicado público",
    sixthRadicado: resultDetection.sixthRadicado,
    samples: resultDetection.samples
  };
}

