async function findDetailPage(context, fallbackPage, expectedRadicado) {
  const openPages = context.pages().filter((p) => !p.isClosed());

  for (let i = openPages.length - 1; i >= 0; i--) {
    const candidatePage = openPages[i];

    if (await isDetailPage(candidatePage, expectedRadicado)) {
      return candidatePage;
    }
  }

  if (await isDetailPage(fallbackPage, expectedRadicado)) {
    return fallbackPage;
  }

  const currentText = await getBodyText(fallbackPage);

  throw new Error(
    "No se encontró página de detalle válida para descargar DOCX. Radicado esperado: " +
      expectedRadicado +
      ". Texto pantalla: " +
      currentText.slice(0, 2500)
  );
}

