function validateDownloadedFile(docFilePath, expectedRadicado) {
  if (!fs.existsSync(docFilePath)) {
    throw new Error("El archivo DOCX no fue guardado correctamente: " + docFilePath);
  }

  const stat = fs.statSync(docFilePath);

  if (!stat.size || stat.size < 500) {
    throw new Error("El archivo DOCX está vacío o incompleto. Tamaño: " + stat.size + " bytes.");
  }

  const buffer = fs.readFileSync(docFilePath);
  const header = buffer.subarray(0, 2).toString("utf8");
  const probe = buffer.subarray(0, Math.min(buffer.length, 50000)).toString("latin1");

  const isDocx =
    header === "PK" &&
    (
      probe.includes("word/document.xml") ||
      probe.includes("[Content_Types].xml")
    );

  if (!isDocx) {
    const textProbe = cleanText(buffer.toString("utf8").slice(0, 8000));

    if (
      textProbe.includes("CONSULTA DE PROCESOS") &&
      textProbe.includes("NACIONAL UNIFICADA") &&
      !textProbe.includes("REPORTE DEL PROCESO")
    ) {
      throw new Error("El archivo descargado sigue siendo el listado general, no el reporte del proceso.");
    }

    if (!digitsOnly(textProbe).includes(expectedRadicado)) {
      throw new Error(
        "El archivo descargado no contiene el radicado esperado. Radicado: " +
          expectedRadicado +
          ". Muestra: " +
          textProbe.slice(0, 2000)
      );
    }
  }

  return {
    sizeBytes: stat.size,
    isDocx
  };
}

